import pygame
import sys
import time
import random

pygame.init()

white = (255, 255, 255)
black = (0, 0, 0)
red = (255, 0, 0)
green = (0, 255, 0)
blue = (0, 0, 255)

display_width = 800
display_height = 600

gameDisplay = pygame.display.set_mode((display_width, display_height))
pygame.display.set_caption('Snake Game')

clock = pygame.time.Clock()

snake_list = []
snake_length = 1

snake_pos = [100, 50]
food_pos = [random.randrange(1, (display_width//10)) * 10, random.randrange(1, (display_height//10)) * 10]

direction = 'RIGHT'
change_dir = direction

while True:
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            pygame.quit()
            sys.exit()
        if event.type == pygame.KEYDOWN:
            if event.key == pygame.K_RIGHT or event.key == ord('d'):
                change_dir = 'RIGHT'
            if event.key == pygame.K_LEFT or event.key == ord('a'):
                change_dir = 'LEFT'
            if event.key == pygame.K_UP or event.key == ord('w'):
                change_dir = 'UP'
            if event.key == pygame.K_DOWN or event.key == ord('s'):
                change_dir = 'DOWN'
            if event.key == pygame.K_ESCAPE:
                pygame.quit()
                sys.exit()

    if change_dir == 'RIGHT' and direction != 'LEFT':
        direction = 'RIGHT'
    if change_dir == 'LEFT' and direction != 'RIGHT':
        direction = 'LEFT'
    if change_dir == 'UP' and direction != 'DOWN':
        direction = 'UP'
    if change_dir == 'DOWN' and direction != 'UP':
        direction = 'DOWN'

    if direction == 'RIGHT':
        snake_pos[0] += 10
    if direction == 'LEFT':
        snake_pos[0] -= 10
    if direction == 'UP':
        snake_pos[1] -= 10
    if direction == 'DOWN':
        snake_pos[1] += 10

    snake_list.insert(0, list(snake_pos))
    if snake_pos[0] == food_pos[0] and snake_pos[1] == food_pos[1]:
        food_pos = [random.randrange(1, (display_width//10)) * 10, random.randrange(1, (display_height//10)) * 10]
        snake_length += 1
    else:
        snake_list.pop()

    if (snake_pos[0] < 0 or snake_pos[0] > display_width-10) or (snake_pos[1] < 0 or snake_pos[1] > display_height-10):
        pygame.quit()
        sys.exit()
    for block in snake_list[1:]:
        if snake_pos[0] == block[0] and snake_pos[1] == block[1]:
            pygame.quit()
            sys.exit()

    gameDisplay.fill(black)
    for x in snake_list:
        pygame.draw.rect(gameDisplay, green, pygame.Rect(x[0], x[1], 10, 10))
    pygame.draw.rect(gameDisplay, red, pygame.Rect(food_pos[0], food_pos[1], 10, 10))

    pygame.display.flip()
    clock.tick(10)

