import pygame
import sys
import random
import time

pygame.init()

width, height = 800, 600
screen = pygame.display.set_mode((width, height))
pygame.display.set_caption('Snake Game')
clock = pygame.time.Clock()
font = pygame.font.Font(None, 36)

class SnakeGame:
    def __init__(self):
        self.snake = [(200, 200), (220, 200), (240, 200)]
        self.direction = 'right'
        self.food = self.generate_food()

    def generate_food(self):
        while True:
            food = (random.randint(0, width - 20) // 20 * 20, random.randint(0, height - 20) // 20 * 20)
            if food not in self.snake:
                return food

    def update(self):
        head = self.snake[-1]
        if self.direction == 'right':
            new_head = (head[0] + 20, head[1])
        elif self.direction == 'left':
            new_head = (head[0] - 20, head[1])
        elif self.direction == 'up':
            new_head = (head[0], head[1] - 20)
        elif self.direction == 'down':
            new_head = (head[0], head[1] + 20)

        self.snake.append(new_head)
        if self.snake[-1] == self.food:
            self.food = self.generate_food()
        else:
            self.snake.pop(0)

        if (self.snake[-1][0] < 0 or self.snake[-1][0] >= width or
            self.snake[-1][1] < 0 or self.snake[-1][1] >= height or
            self.snake[-1] in self.snake[:-1]):
            return False
        return True

    def draw(self):
        screen.fill((0, 0, 0))
        for pos in self.snake:
            pygame.draw.rect(screen, (0, 255, 0), (pos[0], pos[1], 20, 20))
        pygame.draw.rect(screen, (255, 0, 0), (self.food[0], self.food[1], 20, 20))
        text = font.render(f'Score: {len(self.snake)}', True, (255, 255, 255))
        screen.blit(text, (10, 10))
        pygame.display.flip()

def main():
    game = SnakeGame()
    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_LEFT and game.direction != 'right':
                    game.direction = 'left'
                elif event.key == pygame.K_RIGHT and game.direction != 'left':
                    game.direction = 'right'
                elif event.key == pygame.K_UP and game.direction != 'down':
                    game.direction = 'up'
                elif event.key == pygame.K_DOWN and game.direction != 'up':
                    game.direction = 'down'

        if not game.update():
            screen.fill((0, 0, 0))
            text = font.render('Game Over', True, (255, 255, 255))
            screen.blit(text, (width // 2 - 50, height // 2 - 18))
            pygame.display.flip()
            time.sleep(1)
            break

        game.draw()
        clock.tick(10)

if __name__ == '__main__':
    main()

