            pygame.draw.rect(display, snake_color, (pos[0], pos[1], 20, 20))

    def draw_food(self):
        pygame.draw.rect(display, food_color, (self.food[0], self.food[1], 20, 20))

    def draw_score(self):
        text = font.render(f'Score: {self.score}', True, score_color)
        display.blit(text, (10, 10))

    def update(self):
        head = self.snake[-1]
        if self.direction == 'right':
            new_head = (head[0] + 20, head[1])
        elif self.direction == 'left':
            new_head = (head[0] - 20, head[1])
        elif self.direction == 'up':
            new_head = (head[0], head[1] - 20)
        elif self.direction == 'down':
            new_head = (head[0], head[1] + 20)

        self.snake.append(new_head)

        if self.snake[-1] == self.food:
            self.score += 1
            self.food = self.generate_food()
        else:
            self.snake.pop(0)

        if (self.snake[-1][0] < 0 or self.snake[-1][0] >= width or
            self.snake[-1][1] < 0 or self.snake[-1][1] >= height or
            self.snake[-1] in self.snake[:-1]):
            return False
        return True

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            elif event.type == pygame.KEYDOWN:
                if event.key == pygame.K_UP and self.direction != 'down':
                    self.direction = 'up'
                elif event.key == pygame.K_DOWN and self.direction != 'up':
                    self.direction = 'down'
                elif event.key == pygame.K_LEFT and self.direction != 'right':
                    self.direction = 'left'
                elif event.key == pygame.K_RIGHT and self.direction != 'left':
                    self.direction = 'right'

    def play(self):
        while True:
            self.handle_events()
            display.fill(background_color)
            self.draw_snake()
            self.draw_food()
            self.draw_score()
            pygame.display.update()
            if not self.update():
                break
            clock.tick(10)

