            pygame.draw.rect(win, green, (pos[0], pos[1], 20, 20))
        pygame.draw.rect(win, red, (self.apple[0], self.apple[1], 20, 20))
        text = font.render(f"Score: {len(self.snake)}", True, white)
        win.blit(text, (10, 10))
        pygame.display.update()

