def is_perfect_square(n):
    if n < 0:
        return False
    sqrt = int(n ** 0.5)
    return sqrt * sqrt == n

def check_kaprekar(n):
    if not is_perfect_square(n):
        return False
    digits = [int(d) for d in str(n)]
    digits.sort(reverse=True)
    descending = int(''.join(map(str, digits)))
    digits.sort()
    ascending = int(''.join(map(str, digits)))
    return descending - ascending == n

