    if card_type == "Mastercard":
        if len(card_number)!= 16 or not card_number.isdigit():
            return False
        if not (51 <= int(card_number[:2]) <= 55):
            return False
    elif card_type == "Visa":
        if len(card_number)!= 16 or not card_number.isdigit():
            return False
        if not card_number.startswith("4"):
            return False
    else:
