class BankAccount:
    def __init__(self, balance=0):
        self.balance = balance

    def deposit(self, amount):
        self.balance += amount

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient funds")
        else:
            self.balance -= amount

    def check_balance(self):
        return self.balance

class Customer:
    def __init__(self, name, account):
        self.name = name
        self.account = account

    def __str__(self):
        return f"Customer: {self.name}, Balance: {self.account.check_balance()}"

class Bank:
    def __init__(self, name):
        self.name = name
        self.customers = []

    def add_customer(self, customer):
        self.customers.append(customer)

    def remove_customer(self, customer):
        self.customers.remove(customer)

    def __str__(self):
        return f"Bank: {self.name}, Customers: {len(self.customers)}"

def main():
    bank = Bank("My Bank")
    account = BankAccount(1000)
    customer = Customer("John Doe", account)
    bank.add_customer(customer)
    print(customer)
    account.deposit(500)
    print(customer)
    account.withdraw(200)
    print(customer)
    bank.remove_customer(customer)
    print(bank)

if __name__ == "__main__":
    main()

def calculate_discount(price, discount_percentage):
    return price * (discount_percentage / 100)

def check_eligibility(item_price, total_price, discount_percentage):
    if item_price > 0 and total_price > 0:
        discount_amount = calculate_discount(item_price, discount_percentage)
        if discount_amount > 0:
            return True
        else:
            return False
    else:
        return False

def main():
    item_price = 100
    total_price = 500
    discount_percentage = 10
    if check_eligibility(item_price, total_price, discount_percentage):
        print("The item is eligible for discount")
    else:
        print("The item is not eligible for discount")

main()
